import java.io.*;
import java.util.*;
public class Main {
    static final int MOD = 1_000_000_007;
    static int add(int a,int b){int s=a+b; if(s>=MOD) s-=MOD; return s;}
    static int powMod(int base,int exp,int mod){int res=1%mod; int b=base%mod; while(exp>0){if((exp&1)==1) res = (int)((1L*res*b)%mod); b = (int)((1L*b*b)%mod); exp>>=1;} return res;}
    public static void main(String[] args) throws Exception{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            int[][] dp = new int[N+1][M];
            int[][] ndp = new int[N+1][M];
            dp[0][1%M] = 1;
            for(int i=1;i<=M;i++){
                for(int s=0;s<=N;s++) Arrays.fill(ndp[s],0);
                for(int s=0;s<=N;s++){
                    for(int r=0;r<M;r++) if(dp[s][r]!=0){
                        for(int k=0;k+s<=N;k++){
                            int ns = s+k;
                            int nr = (int)((1L* r * powMod(i,k,M)) % M);
                            ndp[ns][nr] = add(ndp[ns][nr], dp[s][r]);
                        }
                    }
                }
                int[][] tmp = dp; dp = ndp; ndp = tmp;
            }
            for(int r=0;r<M;r++){
                if(r>0) out.append(' ');
                out.append(dp[N][r]);
            }
            if(T>0) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

