import sys
MOD = 1_000_000_007

def pow_mod(base, exp, mod):
    res = 1 % mod
    b = base % mod
    while exp:
        if exp & 1:
            res = (res * b) % mod
        b = (b * b) % mod
        exp >>= 1
    return res

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        dp = [[0]*M for _ in range(N+1)]
        dp[0][1%M] = 1
        for i in range(1, M+1):
            ndp = [[0]*M for _ in range(N+1)]
            for s in range(N+1):
                for r in range(M):
                    val = dp[s][r]
                    if not val:
                        continue
                    maxk = N - s
                    for k in range(maxk+1):
                        ns = s + k
                        nr = (r * pow_mod(i, k, M)) % M
                        ndp[ns][nr] = (ndp[ns][nr] + val) % MOD
            dp = ndp
        out_lines.append(' '.join(str(dp[N][r]) for r in range(M)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

