const fs = require('fs');
const MOD = 1000000007n;
function powMod(base, exp, mod){
  let res = 1n % BigInt(mod);
  let b = BigInt(base % mod);
  let e = BigInt(exp);
  const m = BigInt(mod);
  while(e > 0n){
    if(e & 1n) res = (res * b) % m;
    b = (b * b) % m;
    e >>= 1n;
  }
  return Number(res);
}
